#include <iostream>
#include <string>

int main() {
    int n;
    std::cin >> n;
    for (int i = 0; i < n; ++i) {
        std::string code;
        std::cin >> code;
        if (code == "C1083") {
            std::cout << "missing include directory\n";
        } else if (code == "LNK2019") {
            std::cout << "missing additional dependency\n";
        } else if (code == "LNK1104") {
            std::cout << "missing library directory\n";
        } else if (code == "LNK1112") {
            std::cout << "architecture mismatch\n";
        } else if (code == "RUNTIME") {
            std::cout << "missing dll\n";
        }
    }
    return 0;
}

